<template>
  <div>
    <el-row :gutter="40" class="panel-group">
      <el-col :xs="12" :sm="12" :lg="6" class="card-panel-col">
        <panel-card-summary description="Automation Usage!" icon="chart-line" icon-color="#36a3f7">
          <count-to :start-val="0" :end-val="percentage" :duration="1500" suffix=" %" class="card-panel-num"/>
        </panel-card-summary>
      </el-col>
      <el-col :xs="12" :sm="12" :lg="6" class="card-panel-col">
        <panel-card-summary description="Total Usage" icon="robot" icon-color="#34bfa3">
          <count-to :start-val="0" :end-val="totalUsage" :duration="1500" class="card-panel-num" separator="."/>
        </panel-card-summary>
      </el-col>
      <el-col :xs="12" :sm="12" :lg="6" class="card-panel-col">
        <panel-card-summary description="Total Automation" icon="users" icon-color="#f4516c">
          <count-to :start-val="0" :end-val="totalAutomation" :duration="1500" class="card-panel-num" separator="."/>
        </panel-card-summary>
      </el-col>
      <el-col :xs="12" :sm="12" :lg="6" class="card-panel-col">
        <panel-card-summary description="Last Updated" icon="clock" icon-color="orange">
          <div class="card-panel-num" style="font-size: 16px;margin-bottom: 16px">{{ lastUpdated }}</div>
        </panel-card-summary>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import CountTo from 'vue-count-to'
import panelCardSummary from '../../../components/PanelCollabSummarys/index'
import panelCardCollab from '../../../components/PanelCollab/index'
import { mapActions, mapGetters } from 'vuex'

var moment = require('moment')
export default {
  components: {
    CountTo,
    panelCardSummary,
    panelCardCollab
  },
  data: function() {
    return {
      percentage: 0,
      totalUsage: 0,
      totalAutomation: 0,
      lastUpdated: ''
    }
  },
  computed: {
    ...mapGetters('automationUsage', ['automationUsageSummarys'])
  },
  mounted() {
    this.getAutomationUsageSummarys().then((value) => {
      this.percentage = this.automationUsageSummarys.percentage
      this.totalUsage = this.automationUsageSummarys.totalUsage
      this.totalAutomation = this.automationUsageSummarys.totalAutomation
      this.lastUpdated = moment(this.automationUsageSummarys.lastUpdated).fromNow()
    })
  },
  methods: {
    ...mapActions('automationUsage', ['getAutomationUsageSummarys'])
  }
}
</script>

